-- ========================================================
-- 1. CUSTOM VECTOR MATH PL/pgSQL FUNCTIONS
-- ========================================================

CREATE OR REPLACE FUNCTION dot_product(a double precision[], b double precision[])
RETURNS double precision AS $$
DECLARE
  s double precision := 0;
  i integer;
  len_a integer;
  len_b integer;
  BEGIN
  len_a := cardinality(a);
  len_b := cardinality(b);
  IF len_a IS NULL OR len_b IS NULL OR len_a <> len_b THEN
    RETURN 0;
  END IF;
  FOR i IN 1..len_a LOOP
    s := s + a[i] * b[i];
  END LOOP;
  RETURN s;
END;
$$ LANGUAGE plpgsql IMMUTABLE;


CREATE OR REPLACE FUNCTION magnitude(a double precision[])
RETURNS double precision AS $$
DECLARE
  s double precision := 0;
  i integer;
  len integer;
BEGIN
  len := cardinality(a);
  IF len IS NULL THEN
    RETURN 0;
  END IF;
  FOR i IN 1..len LOOP
    s := s + a[i] * a[i];
  END LOOP;
  RETURN sqrt(s);
END;
$$ LANGUAGE plpgsql IMMUTABLE;


CREATE OR REPLACE FUNCTION cosine_similarity(a double precision[], b double precision[])
RETURNS double precision AS $$
DECLARE
  dp double precision;
  mag_a double precision;
  mag_b double precision;
BEGIN
  dp := dot_product(a, b);
  mag_a := magnitude(a);
  mag_b := magnitude(b);
  IF mag_a = 0 OR mag_b = 0 THEN
    RETURN 0;
  END IF;
  RETURN dp / (mag_a * mag_b);
END;
$$ LANGUAGE plpgsql IMMUTABLE;


-- ========================================================
-- 2. TABLE CREATION DDL (SCHEMAS)
-- ========================================================

DROP TABLE IF EXISTS queries CASCADE;
DROP TABLE IF EXISTS document_chunks CASCADE;
DROP TABLE IF EXISTS documents CASCADE;
DROP TABLE IF EXISTS users CASCADE;

CREATE TABLE users (
    id SERIAL PRIMARY KEY,
    username VARCHAR(100) UNIQUE NOT NULL,
    email VARCHAR(255) NOT NULL,
    status VARCHAR(50) NOT NULL DEFAULT 'active',
    role VARCHAR(50) NOT NULL DEFAULT 'user',
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE documents (
    id SERIAL PRIMARY KEY,
    content TEXT NOT NULL,
    metadata JSONB,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE document_chunks (
    id SERIAL PRIMARY KEY,
    document_id INTEGER REFERENCES documents(id) ON DELETE CASCADE,
    chunk_index INTEGER NOT NULL,
    content TEXT NOT NULL,
    embedding DOUBLE PRECISION[] NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE queries (
    id SERIAL PRIMARY KEY,
    input_query TEXT NOT NULL,
    output_response TEXT NOT NULL,
    routing_decision VARCHAR(50) NOT NULL,
    tools_used JSONB,
    latency DOUBLE PRECISION NOT NULL,
    timestamp TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);


