INSERT INTO documents (id, content, metadata) VALUES (1, 'To deploy the backend IT service, make sure the git branch is merged into ''main''. The CI pipeline will compile the Docker container and run pytest. Deploy the container via Kubernetes using the command: ''kubectl rollout restart deployment/backend-service -n it-helpdesk''. Alembic database migrations (''alembic upgrade head'') are executed automatically during the pod initialization phase.', '{"title": "Backend Service Deployment Guide", "category": "deployment"}'::jsonb);
