INSERT INTO documents (id, content, metadata) VALUES (2, 'IT Corporate Network Configuration and Wifi SSID Setup:
Office Secure Wi-Fi SSID is ''IT-Corp-Secure''. Wi-Fi Security authentication requires WPA3-Enterprise (PEAP/MSCHAPv2) with corporate LDAP credentials. Local VPN Gateway is vpn.internal-corp.net. VPN protocols supported are OpenVPN (Port 1194 UDP) and WireGuard (Port 51820 UDP).', '{"title": "Corporate Wifi and VPN Setup", "category": "network"}'::jsonb);
