INSERT INTO documents (id, content, metadata) VALUES (3, 'Office Printer Setup and Installation Instructions:
To add the corporate high-capacity printer on Windows, open Settings -> Bluetooth & Devices -> Printers & Scanners. Click ''Add device'', then select ''The printer that I want isn''t listed''. Select ''Add a printer using an IP address or hostname''. Enter Device Type: ''TCP/IP Device'' and Hostname/IP: ''192.168.4.150''. Choose Driver: ''HP LaserJet Pro M404-M405'' (Standard PCL6 driver) and print a test page to verify.', '{"title": "Office Printer Installation Guide", "category": "hardware"}'::jsonb);
